# Before (encountered during feature work)
def process_data(d):
    r = []
    for x in d:
        if x > 0:
            r.append(x * 2)
    return r

# After (small improvement, same file, no behavior change)
def process_data(data: list[int]) -> list[int]:
    """Double positive numbers in the input list."""
    return [x * 2 for x in data if x > 0]

class OrderProcessorFacade:
    """Route to modern or legacy based on feature flag."""

    def __init__(self):
        self.legacy = LegacyOrderProcessor()
        self.modern = ModernOrderProcessor()

    def process(self, order):
        if feature_flags.is_enabled("modern_orders") and order.type in ["standard", "premium"]:
            return self.modern.process(order)
        return self.legacy.process(order)
